1	#!/usr/bin/env bun
2	/**
3	 * FeedbackHarvester -- Mine LEARNING signals + failures for recurring cross-cutting patterns,
4	 * cluster by root cause, dedup against existing feedback rules, and queue surviving candidates
5	 * for Nick's approval before anything is written.
6	 *
7	 * Queue-then-approve: the harvester NEVER auto-writes feedback-*.md or MEMORY.md.
8	 * All candidates land in MEMORY/LEARNING/FEEDBACK_QUEUE/ as JSON files.
9	 * Nick approves individually; a separate `approve` command commits the rule.
10	 *
11	 * Commands:
12	 *   harvest              Scan all LEARNING signals + failures, produce candidate queue
13	 *   harvest --dry-run    Preview candidates without writing the queue
14	 *   queue                List current queue (pending + approved + rejected)
15	 *   approve <slug>       Promote a queued candidate to a live feedback-*.md rule
16	 *   reject <slug>        Mark a queued candidate as rejected (keeps it for audit)
17	 *   status               Summary of corpus + existing rules
18	 *
19	 * Examples:
20	 *   bun FeedbackHarvester.ts harvest --dry-run
21	 *   bun FeedbackHarvester.ts harvest
22	 *   bun FeedbackHarvester.ts queue
23	 *   bun FeedbackHarvester.ts approve verify-before-claiming
24	 *   bun FeedbackHarvester.ts status
25	 */
26	
27	import { parseArgs } from "util";
28	import * as fs from "fs";
29	import * as path from "path";
30	
31	// ============================================================================
32	// Configuration -- no hardcoded paths; everything derives from env or HOME
33	// ============================================================================
34	
35	const HOME = process.env.HOME!;
36	const CLAUDE_DIR = path.join(HOME, ".claude");
37	const PAI_DIR = process.env.PAI_DIR || path.join(CLAUDE_DIR, "PAI");
38	const MEMORY_DIR = path.join(PAI_DIR, "MEMORY");
39	const LEARNING_DIR = path.join(MEMORY_DIR, "LEARNING");
40	
41	// Signal sources
42	const ALGORITHM_LEARNING_DIR = path.join(LEARNING_DIR, "ALGORITHM");
43	const SYSTEM_LEARNING_DIR = path.join(LEARNING_DIR, "SYSTEM");
44	const FAILURES_DIR = path.join(LEARNING_DIR, "FAILURES");
45	const RATINGS_FILE = path.join(LEARNING_DIR, "SIGNALS", "ratings.jsonl");
46	
47	// State / context
48	const STATE_DIR = path.join(MEMORY_DIR, "STATE");
49	const SESSION_NAMES_FILE = path.join(STATE_DIR, "session-names.json");
50	const WORK_FILE = path.join(STATE_DIR, "work.json");
51	
52	// Dedup target: the global memory dir where feedback-*.md files live
53	const CURRENT_USER = process.env.USER || "nicholaswood";
54	const MEMORY_AUTO_DIR = path.join(
55	  CLAUDE_DIR,
56	  "projects",
57	  `-Users-${CURRENT_USER}--claude`,
58	  "memory",
59	);
60	
61	// Queue dir -- separate from KNOWLEDGE queue; this is the feedback promotion queue
62	const FEEDBACK_QUEUE_DIR = path.join(MEMORY_DIR, "LEARNING", "FEEDBACK_QUEUE");
63	
64	// Clustering thresholds
65	const MIN_RECURRENCE = 3; // minimum distinct sources (sessions/projects) for a theme to survive
66	const CONFIDENCE_FILTER_THRESHOLD = 0.4; // ratings rows below this are noise (inference timeouts at 0.3)
67	const MIN_RATING_TO_SIGNAL_ISSUE = 5; // ratings <= this are "low satisfaction" events
68	
69	// ============================================================================
70	// Types
71	// ============================================================================
72	
73	interface RatingRow {
74	  timestamp: string;
75	  rating: number;
76	  session_id: string;
77	  source: "implicit" | "explicit";
78	  sentiment_summary: string;
79	  confidence: number;
80	  comment?: string;
81	  response_preview?: string;
82	}
83	
84	interface LearningSignal {
85	  sourcePath: string;
86	  sourceType: "algorithm" | "system" | "failure" | "rating";
87	  sessionId?: string;
88	  projectSlug?: string;
89	  timestamp: string;
90	  rating?: number;
91	  text: string; // normalised text for clustering
92	  rawContent: string;
93	}
94	
95	interface Cluster {
96	  slug: string;             // kebab-case identifier
97	  theme: string;            // human-readable summary
98	  rootCause: string;        // distilled one-liner
99	  signals: LearningSignal[];
100	  sessionIds: Set<string>;  // distinct sessions
101	  projectSlugs: Set<string>; // distinct projects
102	  evidenceCount: number;
103	}
104	
105	interface FeedbackCandidate {
106	  slug: string;
107	  theme: string;
108	  rootCause: string;
109	  proposedRuleName: string;
110	  proposedRuleBody: string;
111	  evidenceCount: number;
112	  sessions: string[];
113	  projects: string[];
114	  topExamples: string[];
115	  dedupNote: string;
116	  queuedAt: string;
117	  status: "pending" | "approved" | "rejected";
118	}
119	
120	interface ExistingRule {
121	  slug: string;
122	  filePath: string;
123	  name: string;
124	  description: string;
125	  body: string;
126	}
127	
128	// ============================================================================
129	// Helpers
130	// ============================================================================
131	
132	function toKebab(str: string): string {
133	  return str
134	    .toLowerCase()
135	    .replace(/[^a-z0-9\s-]/g, "")
136	    .replace(/\s+/g, "-")
137	    .replace(/-+/g, "-")
138	    .replace(/^-|-$/g, "")
139	    .substring(0, 60);
140	}
141	
142	function parseFrontmatter(content: string): Record<string, string> {
143	  const match = content.match(/^---\n([\s\S]*?)\n---/);
144	  if (!match) return {};
145	  const result: Record<string, string> = {};
146	  for (const line of match[1].split("\n")) {
147	    const colonIdx = line.indexOf(":");
148	    if (colonIdx > 0) {
149	      const key = line.substring(0, colonIdx).trim();
150	      let value = line.substring(colonIdx + 1).trim();
151	      if (value.startsWith('"') && value.endsWith('"')) {
152	        value = value.slice(1, -1);
153	      }
154	      result[key] = value;
155	    }
156	  }
157	  return result;
158	}
159	
160	function loadSessionNames(): Record<string, string> {
161	  if (!fs.existsSync(SESSION_NAMES_FILE)) return {};
162	  try {
163	    return JSON.parse(fs.readFileSync(SESSION_NAMES_FILE, "utf-8"));
164	  } catch {
165	    return {};
166	  }
167	}
168	
169	function loadWorkSessions(): Record<string, { task?: string; sessionName?: string }> {
170	  if (!fs.existsSync(WORK_FILE)) return {};
171	  try {
172	    const raw = JSON.parse(fs.readFileSync(WORK_FILE, "utf-8"));
173	    // work.json has shape { sessions: { slug: { task, sessionName, ... } } }
174	    return raw.sessions || {};
175	  } catch {
176	    return {};
177	  }
178	}
179	
180	function sessionToProject(
181	  sessionId: string,
182	  sessionNames: Record<string, string>,
183	  workSessions: Record<string, { task?: string; sessionName?: string }>,
184	): string {
185	  // Try session-names.json first (id -> name)
186	  const name = sessionNames[sessionId];
187	  if (name) {
188	    // extract project hint from the session name (first 2 words)
189	    return name.split(/\s+/).slice(0, 2).join("-").toLowerCase() || "unknown";
190	  }
191	  // Try work.json by matching partial sessionId
192	  for (const [slug, entry] of Object.entries(workSessions)) {
193	    if (slug.includes(sessionId.substring(0, 8))) {
194	      return entry.sessionName?.split(/\s+/).slice(0, 2).join("-").toLowerCase() || "unknown";
195	    }
196	  }
197	  return "unknown";
198	}
199	
200	function walkDirForMonthFiles(baseDir: string): string[] {
201	  const files: string[] = [];
202	  if (!fs.existsSync(baseDir)) return files;
203	  for (const month of fs.readdirSync(baseDir)) {
204	    const monthPath = path.join(baseDir, month);
205	    try {
206	      if (!fs.statSync(monthPath).isDirectory()) continue;
207	    } catch {
208	      continue;
209	    }
210	    for (const entry of fs.readdirSync(monthPath)) {
211	      files.push(path.join(monthPath, entry));
212	    }
213	  }
214	  return files;
215	}
216	
217	// Failures are directories, not files
218	function walkFailureDirs(baseDir: string): string[] {
219	  const dirs: string[] = [];
220	  if (!fs.existsSync(baseDir)) return dirs;
221	  for (const month of fs.readdirSync(baseDir)) {
222	    const monthPath = path.join(baseDir, month);
223	    try {
224	      if (!fs.statSync(monthPath).isDirectory()) continue;
225	    } catch {
226	      continue;
227	    }
228	    for (const entry of fs.readdirSync(monthPath)) {
229	      const entryPath = path.join(monthPath, entry);
230	      try {
231	        if (fs.statSync(entryPath).isDirectory()) {
232	          dirs.push(entryPath);
233	        }
234	      } catch {
235	        /* skip */
236	      }
237	    }
238	  }
239	  return dirs;
240	}
241	
242	// ============================================================================
243	// Signal Collection
244	// ============================================================================
245	
246	function collectAlgorithmSignals(): LearningSignal[] {
247	  const signals: LearningSignal[] = [];
248	  for (const file of walkDirForMonthFiles(ALGORITHM_LEARNING_DIR)) {
249	    if (!file.endsWith(".md")) continue;
250	    try {
251	      const content = fs.readFileSync(file, "utf-8");
252	      const fm = parseFrontmatter(content);
253	      const rating = fm.rating ? parseInt(fm.rating) : undefined;
254	      // Strip frontmatter, collect body text
255	      const body = content.replace(/^---[\s\S]*?---\n*/, "").trim();
256	      signals.push({
257	        sourcePath: file,
258	        sourceType: "algorithm",
259	        sessionId: fm.session_id,
260	        timestamp: fm.timestamp || "",
261	        rating,
262	        text: body,
263	        rawContent: content,
264	      });
265	    } catch { /* skip */ }
266	  }
267	  return signals;
268	}
269	
270	function collectSystemSignals(): LearningSignal[] {
271	  const signals: LearningSignal[] = [];
272	  for (const file of walkDirForMonthFiles(SYSTEM_LEARNING_DIR)) {
273	    if (!file.endsWith(".md")) continue;
274	    try {
275	      const content = fs.readFileSync(file, "utf-8");
276	      const fm = parseFrontmatter(content);
277	      const rating = fm.rating ? parseInt(fm.rating) : undefined;
278	      const body = content.replace(/^---[\s\S]*?---\n*/, "").trim();
279	      signals.push({
280	        sourcePath: file,
281	        sourceType: "system",
282	        sessionId: fm.session_id,
283	        timestamp: fm.timestamp || "",
284	        rating,
285	        text: body,
286	        rawContent: content,
287	      });
288	    } catch { /* skip */ }
289	  }
290	  return signals;
291	}
292	
293	function collectFailureSignals(): LearningSignal[] {
294	  const signals: LearningSignal[] = [];
295	  for (const dir of walkFailureDirs(FAILURES_DIR)) {
296	    const contextFile = path.join(dir, "CONTEXT.md");
297	    const sentimentFile = path.join(dir, "sentiment.json");
298	    if (!fs.existsSync(contextFile)) continue;
299	    try {
300	      const content = fs.readFileSync(contextFile, "utf-8");
301	      const fm = parseFrontmatter(content);
302	      const slug = path.basename(dir);
303	      // sentiment.json has rating + session_id
304	      let sessionId = fm.session_id;
305	      let rating: number | undefined;
306	      if (fs.existsSync(sentimentFile)) {
307	        try {
308	          const sent = JSON.parse(fs.readFileSync(sentimentFile, "utf-8"));
309	          sessionId = sessionId || sent.session_id;
310	          rating = sent.rating;
311	        } catch { /* skip */ }
312	      }
313	      const body = content.replace(/^---[\s\S]*?---\n*/, "").trim();
314	      signals.push({
315	        sourcePath: dir,
316	        sourceType: "failure",
317	        sessionId,
318	        timestamp: fm.timestamp || "",
319	        rating,
320	        text: `FAILURE: ${slug.replace(/\d{4}-\d{2}-\d{2}-\d{6}_/, "").replace(/-/g, " ")}\n\n${body}`,
321	        rawContent: content,
322	      });
323	    } catch { /* skip */ }
324	  }
325	  return signals;
326	}
327	
328	function collectRatingSignals(): LearningSignal[] {
329	  const signals: LearningSignal[] = [];
330	  if (!fs.existsSync(RATINGS_FILE)) return signals;
331	  try {
332	    const lines = fs.readFileSync(RATINGS_FILE, "utf-8").trim().split("\n");
333	    for (const line of lines) {
334	      if (!line.trim()) continue;
335	      try {
336	        const row = JSON.parse(line) as RatingRow;
337	        // CRITICAL: filter noise rows from inference timeouts
338	        if (row.confidence <= CONFIDENCE_FILTER_THRESHOLD) continue;
339	        if (!row.sentiment_summary || row.sentiment_summary.startsWith("Inference failed")) continue;
340	        if (row.rating > MIN_RATING_TO_SIGNAL_ISSUE) continue; // only collect low-satisfaction rows
341	        signals.push({
342	          sourcePath: RATINGS_FILE,
343	          sourceType: "rating",
344	          sessionId: row.session_id,
345	          timestamp: row.timestamp,
346	          rating: row.rating,
347	          text: `Rating ${row.rating}/10: ${row.sentiment_summary}`,
348	          rawContent: line,
349	        });
350	      } catch { /* skip malformed */ }
351	    }
352	  } catch { /* file read error */ }
353	  return signals;
354	}
355	
356	// ============================================================================
357	// Existing rule loading (dedup target)
358	// ============================================================================
359	
360	function loadExistingRules(): ExistingRule[] {
361	  const rules: ExistingRule[] = [];
362	  if (!fs.existsSync(MEMORY_AUTO_DIR)) return rules;
363	  for (const file of fs.readdirSync(MEMORY_AUTO_DIR)) {
364	    if (!file.startsWith("feedback-") || !file.endsWith(".md")) continue;
365	    const filePath = path.join(MEMORY_AUTO_DIR, file);
366	    try {
367	      const content = fs.readFileSync(filePath, "utf-8");
368	      const fm = parseFrontmatter(content);
369	      const body = content.replace(/^---[\s\S]*?---\n*/, "").trim();
370	      rules.push({
371	        slug: file.replace(/\.md$/, ""),
372	        filePath,
373	        name: fm.name || file.replace(/\.md$/, ""),
374	        description: fm.description || "",
375	        body,
376	      });
377	    } catch { /* skip */ }
378	  }
379	  return rules;
380	}
381	
382	// ============================================================================
383	// Clustering -- keyword-based root-cause grouping
384	// (No LLM calls here; this is a pure bun tool. Clusters are defined by
385	// recurring patterns in the text. If the corpus grows, an LLM pass can
386	// replace this, but the queue-then-approve gate is the safety net either way.)
387	// ============================================================================
388	
389	// Root-cause patterns: each entry has a slug, a theme label, a root-cause
390	// statement, and regexes. A signal falls into the first matching bucket.
391	const ROOT_CAUSE_PATTERNS: Array<{
392	  slug: string;
393	  theme: string;
394	  rootCause: string;
395	  patterns: RegExp[];
396	}> = [
397	  {
398	    slug: "verify-before-claiming",
399	    theme: "Claiming done without verification",
400	    rootCause: "Assistant reports completion without checking the artefact exists or the action landed.",
401	    patterns: [
402	      /claim(?:ed|ing)?\s+(?:done|complete|finished|handed.off|delegated)/i,
403	      /assert(?:ed|ing)?\s+(?:complete|done|finished)/i,
404	      /report(?:ed|ing)?\s+(?:done|complete|handed)/i,
405	      /verify before claim/i,
406	      /never checked/i,
407	      /without.+verif/i,
408	      /didn.t.+verify/i,
409	      /failed to verify/i,
410	    ],
411	  },
412	  {
413	    slug: "template-content-not-real-data",
414	    theme: "Acting on template/placeholder content as if it were real data",
415	    rootCause: "Analysis or recommendations based on boilerplate or placeholder text rather than the user's actual state.",
416	    patterns: [
417	      /template content/i,
418	      /placeholder/i,
419	      /sample.+data/i,
420	      /not real data/i,
421	      /bootstrap default/i,
422	      /based on template/i,
423	      /template.+not.+actual/i,
424	    ],
425	  },
426	  {
427	    slug: "missed-question",
428	    theme: "Missing or misinterpreting the actual question",
429	    rootCause: "Response answered an adjacent or assumed question rather than what was literally asked.",
430	    patterns: [
431	      /missed the question/i,
432	      /not what.+asked/i,
433	      /asking again/i,
434	      /user.+asking.+again/i,
435	      /previous.+response.+missed/i,
436	      /didn.t.+answer/i,
437	      /failed to answer/i,
438	      /misunderstood/i,
439	    ],
440	  },
441	  {
442	    slug: "fragmented-incomplete-response",
443	    theme: "Fragmented or incomplete responses",
444	    rootCause: "Response was cut off, structurally fragmented, or missing a direct answer.",
445	    patterns: [
446	      /fragmented/i,
447	      /incomplete response/i,
448	      /cut off/i,
449	      /previous response was incomplete/i,
450	      /seeking clarification on unclear recommendation/i,
451	      /unclear recommendation/i,
452	      /previous response was fragmented/i,
453	    ],
454	  },
455	  {
456	    slug: "unsolicited-framing",
457	    theme: "Pushing a framing the user explicitly rejected",
458	    rootCause: "Continued recommending an approach after the user pushed back on it.",
459	    patterns: [
460	      /pushback/i,
461	      /over.+repeating/i,
462	      /keeps? suggesting/i,
463	      /already rejected/i,
464	      /wants.+not.+workstation/i,
465	      /not what.+wants/i,
466	      /user.+doesn.t want/i,
467	      /thin.?client/i,
468	    ],
469	  },
470	  {
471	    slug: "stale-context",
472	    theme: "Using stale or cached context rather than re-reading live state",
473	    rootCause: "Answer was based on outdated file content, logs, or memory rather than current on-disk state.",
474	    patterns: [
475	      /stale/i,
476	      /cached/i,
477	      /outdated/i,
478	      /old.+log/i,
479	      /read stale/i,
480	      /log.+earlier/i,
481	      /not re.?check/i,
482	      /without.+re.?read/i,
483	    ],
484	  },
485	  {
486	    slug: "over-recommending",
487	    theme: "Over-recommending or over-explaining beyond what was asked",
488	    rootCause: "Padded response with unrequested suggestions, caveats, or explanations.",
489	    patterns: [
490	      /over.?engineer/i,
491	      /too complex/i,
492	      /unnecessary/i,
493	      /didn.t ask/i,
494	      /not asked for/i,
495	      /unsolicited/i,
496	      /over.?explain/i,
497	    ],
498	  },
499	];
500	
501	function clusterSignals(
502	  signals: LearningSignal[],
503	  sessionNames: Record<string, string>,
504	  workSessions: Record<string, { task?: string; sessionName?: string }>,
505	): Cluster[] {
506	  const clusterMap = new Map<string, Cluster>();
507	
508	  // Initialise cluster buckets
509	  for (const pattern of ROOT_CAUSE_PATTERNS) {
510	    clusterMap.set(pattern.slug, {
511	      slug: pattern.slug,
512	      theme: pattern.theme,
513	      rootCause: pattern.rootCause,
514	      signals: [],
515	      sessionIds: new Set(),
516	      projectSlugs: new Set(),
517	      evidenceCount: 0,
518	    });
519	  }
520	
521	  for (const signal of signals) {
522	    for (const pattern of ROOT_CAUSE_PATTERNS) {
523	      const matched = pattern.patterns.some(re => re.test(signal.text));
524	      if (!matched) continue;
525	
526	      const cluster = clusterMap.get(pattern.slug)!;
527	      cluster.signals.push(signal);
528	      cluster.evidenceCount++;
529	
530	      if (signal.sessionId) {
531	        cluster.sessionIds.add(signal.sessionId);
532	        const project = sessionToProject(signal.sessionId, sessionNames, workSessions);
533	        cluster.projectSlugs.add(project);
534	      } else {
535	        // Failure dirs without sessionId still count as a distinct source
536	        cluster.projectSlugs.add(`failure:${path.basename(signal.sourcePath).substring(0, 30)}`);
537	      }
538	    }
539	  }
540	
541	  // Return only clusters with enough recurrence
542	  return Array.from(clusterMap.values()).filter(
543	    c => c.signals.length > 0 && (c.sessionIds.size + c.projectSlugs.size) >= MIN_RECURRENCE
544	  );
545	}
546	
547	// ============================================================================
548	// Dedup check
549	// ============================================================================
550	
551	function dedupCheck(cluster: Cluster, existingRules: ExistingRule[]): string {
552	  for (const rule of existingRules) {
553	    if (rule.slug === `feedback-${cluster.slug}`) {
554	      return `COVERED -- feedback-${cluster.slug}.md already exists.`;
555	    }
556	    // Fuzzy check: if the cluster slug keywords appear heavily in the rule body
557	    const slugWords = cluster.slug.split("-").filter(w => w.length > 3);
558	    const bodyLower = rule.body.toLowerCase();
559	    const hits = slugWords.filter(w => bodyLower.includes(w)).length;
560	    if (hits >= Math.ceil(slugWords.length * 0.6)) {
561	      return `LIKELY COVERED by ${rule.slug} (keyword overlap ${hits}/${slugWords.length}).`;
562	    }
563	  }
564	  return "NEW -- no existing rule covers this theme.";
565	}
566	
567	// ============================================================================
568	// Candidate drafting
569	// ============================================================================
570	
571	function draftCandidate(cluster: Cluster, dedupNote: string): FeedbackCandidate {
572	  const topExamples = cluster.signals
573	    .slice(0, 3)
574	    .map(s => s.text.split("\n").find(l => l.trim().length > 20) || s.text.substring(0, 120));
575	
576	  // Build a proposed rule body that matches the feedback-*.md format
577	  const proposedRuleBody = `${cluster.rootCause}
578	
579	**Why:** Evidence from ${cluster.evidenceCount} signal(s) across ${cluster.sessionIds.size} session(s) and ${cluster.projectSlugs.size} project(s). Recurring root cause: ${cluster.theme}.
580	
581	**How to apply:** ${buildApplyGuidance(cluster.slug)}
582	
583	**Evidence examples:**
584	${topExamples.map(e => `- "${e.substring(0, 100).replace(/\n/g, " ")}"`).join("\n")}`;
585	
586	  return {
587	    slug: cluster.slug,
588	    theme: cluster.theme,
589	    rootCause: cluster.rootCause,
590	    proposedRuleName: `feedback-${cluster.slug}`,
591	    proposedRuleBody,
592	    evidenceCount: cluster.evidenceCount,
593	    sessions: Array.from(cluster.sessionIds),
594	    projects: Array.from(cluster.projectSlugs),
595	    topExamples,
596	    dedupNote,
597	    queuedAt: new Date().toISOString(),
598	    status: "pending",
599	  };
600	}
601	
602	function buildApplyGuidance(slug: string): string {
603	  const guidance: Record<string, string> = {
604	    "verify-before-claiming": "Before using done, complete, handed off, delegated, or landed, verify the artefact exists or the action returned. If you cannot verify, say so explicitly rather than asserting completion.",
605	    "template-content-not-real-data": "Before analysing or making recommendations about a user's context, confirm you are reading their actual populated data, not a sample or template file. Look for placeholder markers like {{PLACEHOLDER}}, (sample), or skeleton comments.",
606	    "missed-question": "Re-read the user's message before responding. Confirm which question is being answered. If a question was already asked and not answered, answer it directly first.",
607	    "fragmented-incomplete-response": "Ensure responses have a direct answer before supporting detail. Never cut off mid-sentence. If context is nearly full, say so and summarise rather than truncating silently.",
608	    "unsolicited-framing": "If the user has rejected a framing or recommendation, drop it. Do not re-introduce it in a later turn unless the user brings it back.",
609	    "stale-context": "When acting on file content or log output, re-read the live file rather than relying on earlier read results. Logs especially change; re-fetch before referencing.",
610	    "over-recommending": "Answer what was asked. Only add unrequested advice when it is genuinely critical. Default to the minimal sufficient response.",
611	  };
612	  return guidance[slug] || "Apply the root cause analysis to avoid repeating the identified failure shape.";
613	}
