619	function loadQueue(): FeedbackCandidate[] {
620	  if (!fs.existsSync(FEEDBACK_QUEUE_DIR)) return [];
621	  const candidates: FeedbackCandidate[] = [];
622	  for (const file of fs.readdirSync(FEEDBACK_QUEUE_DIR)) {
623	    if (!file.endsWith(".json")) continue;
624	    try {
